+func TestParseBrCreateID(t *testing.T) {
+	tests := []struct {
+		name    string
+		input   string
+		wantID  string
+		wantErr bool
+	}{
+		{
+			name:   "array format",
+			input:  `[{"id":"bd-abc123"}]`,
+			wantID: "bd-abc123",
+		},
+		{
+			name:   "object format",
+			input:  `{"id":"bd-xyz789"}`,
+			wantID: "bd-xyz789",
+		},
+		{
+			name:   "array with extra fields",
+			input:  `[{"id":"bd-test","title":"Test","status":"open"}]`,
+			wantID: "bd-test",
+		},
+		{
+			name:    "empty array",
+			input:   `[]`,
+			wantErr: true,
+		},
+		{
+			name:    "array with empty id",
+			input:   `[{"id":""}]`,
+			wantErr: true,
+		},
+		{
+			name:    "invalid json",
+			input:   `not json`,
+			wantErr: true,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			id, err := parseBrCreateID([]byte(tt.input))
+			if tt.wantErr {
+				if err == nil {
+					t.Errorf("expected error, got id=%q", id)
+				}
+				return
+			}
+			if err != nil {
+				t.Errorf("unexpected error: %v", err)
+				return
+			}
+			if id != tt.wantID {
+				t.Errorf("parseBrCreateID = %q, want %q", id, tt.wantID)
+			}
+		})
+	}
+}
